17 | package com.ibm.jp.automation.e2m;
18 | 
19 | import picocli.CommandLine;
20 | import picocli.CommandLine.Command;
21 | import picocli.CommandLine.ITypeConverter;
22 | import picocli.CommandLine.Option;
23 | import picocli.CommandLine.Parameters;
24 | 
25 | import java.io.BufferedReader;
26 | import java.io.File;
27 | import java.io.InputStreamReader;
28 | import java.nio.file.Path;
29 | import java.util.List;
30 | import java.util.concurrent.Callable;
31 | import java.util.regex.Pattern;
32 | 
33 | @Command(name = "e2m", description = "Eclipse project to Maven project converter", version = "1.0", mixinStandardHelpOptions = true)
34 | public class Main implements Callable<Integer> {
35 | 
36 |     /** コマンドライン引数のコピー（デバッグ ZIP 用）。 */
37 |     private String[] rawArgs;
38 | 
39 |     @Option(names = {"-g", "--groupId"}, required = false, description = "Maven groupId of the output project")
40 |     private String groupId;
41 | 
42 |     @Option(names = {"-a", "--artifactId"}, required = false, description = "Maven artifactId of the output project")
43 |     private String artifactId;
44 | 
45 |     @Option(names = {"-v", "--artifactVersion"}, required = false, description = "Maven version of the output project (default: 1.0-SNAPSHOT)")
46 |     private String artifactVersion;
47 |     private static final String DEFAULT_ARTIFACT_VERSION = "1.0-SNAPSHOT";
48 | 
49 |     @Option(names = {"--javaTargetVersion"}, required = false, converter = JavaVersionConverter.class,
50 |             description = "Override maven.compiler.target in the generated pom.xml (default: taken from the Eclipse project settings)")
51 |     private JavaVersion javaTargetVersion;
52 | 
53 |     @Option(names = {"--debug"}, description = "Output debug information as e2m_debug_<datetime>.zip in the output directory")
54 |     private boolean debug;
55 | 
56 |     @Parameters(index = "0", paramLabel = "<inputDir>", description = "Eclipse project directory to convert")
57 |     private File inputDir;
58 | 
59 |     @Parameters(index = "1", paramLabel = "<outputDir>", description = "Output directory for the Maven project")
60 |     private File outputDir;
61 | 
62 |     public static void main(String[] args) {
63 |         Main main = new Main();
64 |         main.rawArgs = args.clone();
65 |         System.exit(new CommandLine(main).execute(args));
66 |     }
67 | 
68 |     @Override
69 |     public Integer call() {
70 |         Path inputPath = inputDir.toPath();
71 | 
72 |         // 1. 引数の確認
73 |         if (!inputDir.isDirectory()) {
74 |             System.err.println("[ERROR] 入力ディレクトリが見つかりません: " + inputDir);
75 |             return 1;
76 |         }
77 |         if (!inputPath.resolve(".project").toFile().exists()) {
78 |             System.err.println("[ERROR] Eclipseプロジェクトではありません (.project ファイルが見つかりません): " + inputDir);
79 |             return 1;
80 |         }
81 |         if (outputDir.exists() && !outputDir.isDirectory()) {
82 |             System.err.println("[ERROR] 出力パスはディレクトリである必要があります: " + outputDir);
83 |             return 1;
84 |         }
85 |         if (javaTargetVersion != null && javaTargetVersion.isUnknown()) {
86 |             System.err.println("[ERROR] --javaTargetVersionが不正です: " + javaTargetVersion);
87 |             return 1;
88 |         }
89 | 
90 |         try {
91 |             // 2. Eclipseプロジェクト情報をパース
92 |             System.out.println("\n[1/5] Eclipseプロジェクトを解析中...");
93 |             EclipseProject eclipseProject = EclipseProjectParser.parse(inputPath);
94 |             System.out.println("  プロジェクト名: " + eclipseProject.projectName());
95 |             System.out.println("  種別: " + (eclipseProject.webProject() ? "Webプロジェクト (WTP)" : "Javaプロジェクト"));
96 |             System.out.println("  Javaソースバージョン: " + eclipseProject.javaSourceVersion());
97 |             System.out.println("  Javaターゲットバージョン: " + eclipseProject.javaTargetVersion());
98 |             if (eclipseProject.webProject()) {
99 |                 System.out.println("  Web仕様バージョン: " + eclipseProject.webVersion());
100 |             }
101 |             System.out.println("  ソースフォルダ: " + eclipseProject.sourceFolders());
102 |             if (eclipseProject.webProject()) {
103 |                 System.out.println("  Webコンテンツフォルダ: " + eclipseProject.webContentRoot());
104 |             }
105 |             System.out.println("  JARファイル数: " + eclipseProject.jarPaths().size());
106 | 
107 |             if (eclipseProject.javaSourceVersion().isUnknown()) {
108 |                 System.err.println("[ERROR] Javaソースバージョンを認識できませんでした: "
109 |                         + eclipseProject.javaSourceVersion());
110 |                 return 1;
111 |             }
112 | 
113 |             System.out.println("\n[2/5] 移行先のMavenプロジェクトを決定中...");
114 |             String defaultArtifactId = convertToArtifactId(eclipseProject.projectName());
115 |             if (groupId == null || groupId.isBlank()) {
116 |                 // オプション未指定の場合は対話的に入力を受け付ける
117 |                 try (BufferedReader reader = new BufferedReader(new InputStreamReader(System.in))) {
118 |                     groupId = promptIfAbsent(reader, "groupId", groupId, null);
119 |                     artifactId = promptIfAbsent(reader, "artifactId", artifactId, defaultArtifactId);
120 |                     artifactVersion = promptIfAbsent(reader, "artifactVersion", artifactVersion, DEFAULT_ARTIFACT_VERSION);
121 |                 }
122 |             } else {
123 |                 // 少なくとも--groupIdが指定されていれば，あとは空ならデフォルトを使用する
124 |                 if (artifactId == null || artifactId.isBlank()) {
125 |                     artifactId = defaultArtifactId;
126 |                 }
127 |                 if (artifactVersion == null || artifactId.isBlank()) {
128 |                     artifactVersion = DEFAULT_ARTIFACT_VERSION;
129 |                 }
130 |                 System.out.println("groupId: " + groupId);
131 |                 System.out.println("artifactId: " + artifactId);
132 |                 System.out.println("version: " + artifactVersion);
133 |             }
134 | 
135 |             // 出力先は outputDir/artifactId
136 |             Path outputPath = outputDir.toPath().resolve(artifactId);
137 |             if (outputPath.toFile().exists()) {
138 |                 System.err.println("[ERROR] 出力先ディレクトリがすでに存在しています: " + outputPath);
139 |                 return 1;
140 |             }
141 | 
142 |             System.out.println("\n=== e2m: Eclipse → Maven 変換開始 ===");
143 |             System.out.println("  入力: " + inputPath.toAbsolutePath());
144 |             System.out.println("  出力: " + outputPath.toAbsolutePath());
145 | 
146 |             // 3.(続き) JAR依存関係を解決
147 |             System.out.println("\n[3/5] JAR依存関係を解決中...");
148 |             List<MavenDependency> dependencies = DependencyResolver.resolve(eclipseProject.jarPaths(), inputPath);
149 |             long found = dependencies.stream().filter(d -> !"system".equals(d.scope())).count();
150 |             long system = dependencies.stream().filter(d -> "system".equals(d.scope())).count();
151 |             System.out.println("  Maven Central で見つかった依存: " + found + " 件");
152 |             System.out.println("  system スコープの依存: " + system + " 件");
153 | 
154 |             // 4. pom.xml を生成
155 |             System.out.println("\n[4/5] pom.xml を生成中...");
156 |             // --javaTargetVersion が指定された場合はソースバージョンと比較してバリデーション
157 |             JavaVersion sourceVer = eclipseProject.javaSourceVersion();
158 |             if (javaTargetVersion != null) {
159 |                 if (!sourceVer.isUnknown() && javaTargetVersion.compareTo(sourceVer) < 0) {
160 |                     System.err.println("[ERROR] --javaTargetVersion (" + javaTargetVersion
161 |                             + ") はJavaソースバージョン (" + eclipseProject.javaSourceVersion()
162 |                             + ") より低いバージョンを指定することはできません。");
163 |                     return 1;
164 |                 }
165 |             }
166 |             PomGenerator.generate(eclipseProject, dependencies, groupId, artifactId, artifactVersion,
167 |                     javaTargetVersion, outputPath);
168 | 
169 |             // 5. ソース・Webコンテンツをコピー
170 |             System.out.println("\n[5/5] ソースファイルをコピー中...");
171 |             ProjectCopier.copy(eclipseProject, dependencies, inputPath, outputPath);
172 | 
173 |             System.out.println("\n=== 変換完了 ===");
174 |             System.out.println("出力先: " + outputPath.toAbsolutePath());
175 | 
176 |             // --debug オプション: デバッグ ZIP を生成
177 |             if (debug) {
178 |                 DebugArchiver.archive(inputPath, outputDir.toPath(), outputPath, rawArgs);
179 |             }
180 | 
181 |             return 0;
182 | 
183 |         } catch (Exception e) {
184 |             System.err.println("[ERROR] 変換中にエラーが発生しました: " + e.getMessage());
185 |             e.printStackTrace(System.err);
186 |             return 2;
187 |         }
188 |     }
189 | 
190 |     /**
191 |      * 引数が null または空の場合にプロンプトを表示して入力を受け付ける。
192 |      * デフォルト値がある場合は "[default]" 形式で表示し、空入力でデフォルト値を採用する。
193 |      *
194 |      * @param reader       入力ストリーム
195 |      * @param name         項目名（表示用）
196 |      * @param value        コマンドライン引数の値（null または空の場合にプロンプト表示）
197 |      * @param defaultValue デフォルト値（null の場合はデフォルトなし）
198 |      * @return 確定した値
199 |      */
200 |     private static String promptIfAbsent(BufferedReader reader, String name,
201 |             String value, String defaultValue) throws Exception {
202 |         if (value != null && !value.isBlank()) {
203 |             return value;
204 |         }
205 |         while (true) {
206 |             if (defaultValue != null) {
207 |                 System.out.print(name + " [" + defaultValue + "]: ");
208 |             } else {
209 |                 System.out.print(name + ": ");
210 |             }
211 |             System.out.flush();
212 |             String line = reader.readLine();
213 |             if (line == null) {
214 |                 // EOF（パイプ等）の場合はデフォルト値を使用
215 |                 return defaultValue != null ? defaultValue : "";
216 |             }
217 |             String trimmed = line.trim();
218 |             if (trimmed.isEmpty()) {
219 |                 if (defaultValue != null) {
220 |                     return defaultValue;
221 |                 }
222 |                 System.err.println("  値を入力してください。");
223 |                 continue;
224 |             }
225 |             return trimmed;
226 |         }
227 |     }
228 | 
229 |     // artifactIdとして許可する文字（半角英数字、ハイフン、アンダースコア）以外にマッチする正規表現
230 |     private static final Pattern INVALID_CHARS = Pattern.compile("[^a-z0-9\\-_]");
231 | 
232 |     // キャメルケースの境界（大文字の前）にマッチする正規表現
233 |     private static final Pattern CAMEL_CASE_BOUNDARY = Pattern.compile("(?<=[a-z0-9])(?=[A-Z])");
234 | 
235 |     /**
236 |      * プロジェクト名からMavenのartifactIdとして利用可能な文字列を生成します。
237 |      *
238 |      * @param projectName プロジェクト名
239 |      * @return artifactId用文字列
240 |      */
241 |     public static String convertToArtifactId(String projectName) {
242 |         if (projectName == null || projectName.isBlank()) {
243 |             return "default-artifact";
244 |         }
245 | 
246 |         // 1. パッケージ名が含まれている場合（完全限定名）、最後のクラス名部分だけを抽出
247 |         String simpleName = projectName.substring(projectName.lastIndexOf('.') + 1);
248 | 
249 |         // 2. キャメルケース（OrderManager -> Order-Manager）をハイフン区切りに変換
250 |         String kebabCase = CAMEL_CASE_BOUNDARY.matcher(simpleName).replaceAll("-");
251 | 
252 |         // 3. すべて小文字に変換
253 |         String lowerCase = kebabCase.toLowerCase();
254 | 
255 |         // 4. artifactIdとして使えない文字（日本語や特殊記号など）を完全に除去
256 |         String sanitized = INVALID_CHARS.matcher(lowerCase).replaceAll("");
257 | 
258 |         // 5. 連続したハイフンやアンダースコアを綺麗に整理
259 |         sanitized = sanitized.replaceAll("[-_]{2,}", "-");
260 | 
261 |         // 6. 先頭や末尾にあるハイフン・アンダースコアを除去
262 |         sanitized = sanitized.replaceAll("^[-_]+|[-_]+$", "");
263 | 
264 |         // すべての文字が削られて空になった場合のフォールバック
265 |         return sanitized.isBlank() ? "converted-artifact" : sanitized;
266 |     }
267 | 
268 |     /**
269 |      * picocli 用の {@link JavaVersion} 型変換クラス。
270 |      * 変換に失敗した場合は {@link JavaVersion#UNKNOWN_VERSION} を返す。
271 |      */
272 |     static class JavaVersionConverter implements ITypeConverter<JavaVersion> {
273 |         @Override
274 |         public JavaVersion convert(String value) {
275 |             return JavaVersion.of(value);
276 |         }
277 |     }
278 | }
