17 | package com.ibm.jp.automation.e2m;
18 | 
19 | import java.io.IOException;
20 | import java.nio.file.Files;
21 | import java.nio.file.Path;
22 | import java.nio.file.StandardCopyOption;
23 | import java.util.List;
24 | 
25 | /**
26 |  * EclipseプロジェクトのソースファイルをMavenの標準ディレクトリ構造にコピーするクラス。
27 |  *
28 |  * <ul>
29 |  *   <li>Javaソース (.java) → src/main/java/ または src/test/java/</li>
30 |  *   <li>リソースファイル (非.java) → src/main/resources/ または src/test/resources/</li>
31 |  *   <li>Webコンテンツ (WTPプロジェクトの場合) → src/main/webapp/</li>
32 |  * </ul>
33 |  */
34 | public class ProjectCopier {
35 | 
36 |     private ProjectCopier() {}
37 | 
38 |     /**
39 |      * EclipseプロジェクトのファイルをMaven標準ディレクトリ構造にコピーする。
40 |      *
41 |      * @param eclipseProject パース済みEclipseプロジェクト情報
42 |      * @param dependencies   解決済み依存関係リスト（system スコープの JAR を libs/ にコピーする）
43 |      * @param inputDir       Eclipseプロジェクトのルートディレクトリ
44 |      * @param outputDir      Mavenプロジェクトの出力ルートディレクトリ
45 |      * @throws IOException ファイルコピーに失敗した場合
46 |      */
47 |     public static void copy(EclipseProject eclipseProject, List<MavenDependency> dependencies,
48 |                             Path inputDir, Path outputDir) throws IOException {
49 | 
50 |         // Javaソースフォルダのコピー
51 |         List<String> sourceFolders = eclipseProject.sourceFolders();
52 |         for (String sourceFolder : sourceFolders) {
53 |             Path srcPath = resolveSourcePath(inputDir, sourceFolder);
54 |             if (!Files.isDirectory(srcPath)) {
55 |                 System.out.println("  [WARN] ソースフォルダが見つかりません: " + srcPath);
56 |                 continue;
57 |             }
58 |             boolean isTest = isTestFolder(sourceFolder);
59 |             Path javaDestBase = outputDir.resolve(isTest ? "src/test/java" : "src/main/java");
60 |             Path resourceDestBase = outputDir.resolve(isTest ? "src/test/resources" : "src/main/resources");
61 | 
62 |             copySourceFolder(srcPath, srcPath, javaDestBase, resourceDestBase);
63 |         }
64 | 
65 |         // Webコンテンツのコピー（WTPプロジェクトの場合）
66 |         if (eclipseProject.webProject() && eclipseProject.webContentRoot() != null) {
67 |             Path webContentPath = resolveSourcePath(inputDir, eclipseProject.webContentRoot());
68 |             if (Files.isDirectory(webContentPath)) {
69 |                 Path webappDest = outputDir.resolve("src/main/webapp");
70 |                 // WEB-INF/lib 内のJARは<dependency>として処理済みのためコピー不要（JAR以外はコピーする）
71 |     //            Path webInfLib = webContentPath.resolve("WEB-INF/lib");
72 |                 copyWebContents(webContentPath, webappDest);
73 |                 System.out.println("  Copied web content: " + webContentPath + " → " + webappDest);
74 |             } else {
75 |                 System.out.println("  [WARN] Webコンテンツルートが見つかりません: " + webContentPath);
76 |             }
77 |         }
78 | 
79 |         // system スコープの JAR を libs/ にコピー
80 |         for (MavenDependency dep : dependencies) {
81 |             if ("system".equals(dep.scope()) && dep.systemPath() != null) {
82 |                 Path src = Path.of(dep.systemPath());
83 |                 if (Files.isRegularFile(src)) {
84 |                     Path libsDir = outputDir.resolve("libs");
85 |                     Files.createDirectories(libsDir);
86 |                     Path dest = libsDir.resolve(src.getFileName());
87 |                     Files.copy(src, dest, StandardCopyOption.REPLACE_EXISTING);
88 |                     System.out.println("  Copied JAR to libs/: " + dest.getFileName());
89 |                 }
90 |             }
91 |         }
92 |     }
93 | 
94 |     /**
95 |      * ソースフォルダ内のファイルを.javaとリソースに振り分けてコピーする。
96 |      *
97 |      * @param baseDir      コピー元のルート（相対パス計算の基点）
98 |      * @param currentDir   現在処理中のディレクトリ
99 |      * @param javaDestBase .javaファイルのコピー先ベースディレクトリ
100 |      * @param resourceDest リソースファイルのコピー先ベースディレクトリ
101 |      * @throws IOException ファイルコピーに失敗した場合
102 |      */
103 |     private static void copySourceFolder(Path baseDir, Path currentDir, Path javaDestBase, Path resourceDest)
104 |             throws IOException {
105 |         Files.walk(currentDir)
106 |                 .filter(Files::isRegularFile)
107 |                 .forEach(srcFile -> {
108 |                     try {
109 |                         Path relative = baseDir.relativize(srcFile);
110 |                         boolean isJava = srcFile.getFileName().toString().endsWith(".java");
111 |                         Path destBase = isJava ? javaDestBase : resourceDest;
112 |                         Path destFile = destBase.resolve(relative);
113 |                         Files.createDirectories(destFile.getParent());
114 |                         Files.copy(srcFile, destFile, StandardCopyOption.REPLACE_EXISTING);
115 |                     } catch (IOException e) {
116 |                         throw new RuntimeException("ファイルコピーに失敗しました: " + srcFile, e);
117 |                     }
118 |                 });
119 |         System.out.println("  Copied source folder: " + currentDir + " → " + javaDestBase);
120 |     }
121 | 
122 |     /**
123 |      * ディレクトリを再帰的にコピーする。
124 |      * {@code excludeJarDir} が指定された場合、そのディレクトリ直下の {@code .jar} ファイルのみスキップする。
125 |      *
126 |      * @param srcDir       コピー元ディレクトリ
127 |      * @param destDir      コピー先ディレクトリ
128 |      * @param excludeJarDir このディレクトリ直下の .jar ファイルを除外する（null の場合は除外なし）
129 |      * @throws IOException ファイルコピーに失敗した場合
130 |      */
131 |     private static void copyWebContents(Path srcDir, Path destDir) throws IOException {
132 |         Path excludeJarDir = srcDir.resolve("WEB-INF/lib");
133 |         Files.walk(srcDir)
134 |                 .filter(srcPath -> !srcPath.startsWith(excludeJarDir)
135 |                         || !srcPath.getFileName().toString().endsWith(".jar"))
136 |                 .forEach(srcPath -> {
137 |                     try {
138 |                         Path relative = srcDir.relativize(srcPath);
139 |                         Path destPath = destDir.resolve(relative);
140 |                         if (Files.isDirectory(srcPath)) {
141 |                             Files.createDirectories(destPath);
142 |                         } else {
143 |                             Files.createDirectories(destPath.getParent());
144 |                             Files.copy(srcPath, destPath, StandardCopyOption.REPLACE_EXISTING);
145 |                         }
146 |                     } catch (IOException e) {
147 |                         throw new RuntimeException("ファイルコピーに失敗しました: " + srcPath, e);
148 |                     }
149 |                 });
150 |     }
151 | 
152 |     /**
153 |      * ソースフォルダのパス文字列をinputDir基点の絶対Pathに解決する。
154 |      * 先頭の '/' は除去して相対パスとして扱う。
155 |      */
156 |     private static Path resolveSourcePath(Path inputDir, String folderPath) {
157 |         String normalized = folderPath.startsWith("/") ? folderPath.substring(1) : folderPath;
158 |         if (normalized.isEmpty()) {
159 |             return inputDir;
160 |         }
161 |         return inputDir.resolve(normalized);
162 |     }
163 | 
164 |     /**
165 |      * ソースフォルダ名に "test" が含まれるかどうかを判定する。
166 |      * パスの各セグメントを小文字で比較する。
167 |      */
168 |     static boolean isTestFolder(String folderPath) {
169 |         String lower = folderPath.toLowerCase();
170 |         for (String segment : lower.split("[/\\\\]")) {
171 |             if (segment.equals("test") || segment.startsWith("test-") || segment.endsWith("-test")
172 |                     || segment.contains("test")) {
173 |                 return true;
174 |             }
175 |         }
176 |         return false;
177 |     }
178 | }
