32 | /**
33 |  * Eclipseの.classpathに記載されたJARファイルのSHA1ハッシュを計算し、
34 |  * Maven Central REST APIで依存関係情報を検索するクラス。
35 |  */
36 | public class DependencyResolver {
37 | 
38 |     private static final String MAVEN_SEARCH_URL =
39 |             "https://search.maven.org/solrsearch/select?q=1:%s&rows=1&wt=json";
40 | 
41 | 
42 |     private final HttpClient httpClient;
43 | 
44 |     public DependencyResolver() {
45 |         this.httpClient = HttpClient.newBuilder()
46 |                 .connectTimeout(Duration.ofSeconds(10))
47 |                 .build();
