50 |     /**
51 |      * JARが置かれたディレクトリパスのリストを受け取り、Maven依存関係リストに解決して返す。
52 |      * 各ディレクトリに含まれる全ての {@code .jar} ファイルについて解決を行う。
53 |      *
54 |      * @param jarPaths Eclipseの.classpathから取得したディレクトリパス文字列のリスト
55 |      * @param inputDir Eclipseプロジェクトのルートディレクトリ（相対パス解決の基準）
56 |      * @return 解決済みの {@link MavenDependency} リスト
57 |      */
58 |     public static List<MavenDependency> resolve(List<String> jarPaths, Path inputDir) {
59 |         DependencyResolver resolver = new DependencyResolver();
60 |         List<MavenDependency> results = new ArrayList<>();
61 |         for (String jarPath : jarPaths) {
62 |             Path dir = Path.of(jarPath).isAbsolute()
63 |                     ? Path.of(jarPath)
64 |                     : inputDir.resolve(jarPath);
65 |             if (!Files.isDirectory(dir)) {
66 |                 continue;
67 |             }
68 |             try (var stream = Files.list(dir)) {
69 |                 stream.filter(p -> p.getFileName().toString().endsWith(".jar"))
70 |                       .sorted()
71 |                       .forEach(p -> results.add(resolver.resolveJar(p.toString(), inputDir)));
72 |             } catch (IOException e) {
73 |                 System.err.println("  [WARN] ディレクトリの読み取りに失敗しました: " + dir);
74 |             }
75 |         }
76 |         return results;
77 |     }
