79 |     /**
80 |      * 1つのJARパスを解決する。
81 |      */
82 |     private MavenDependency resolveJar(String jarPath, Path inputDir) {
83 |         Path path = Path.of(jarPath).isAbsolute()
84 |                 ? Path.of(jarPath)
85 |                 : inputDir.resolve(jarPath);
86 | 
87 |         String jarFileName = path.getFileName().toString();
88 |         // 拡張子なしのベース名
89 |         String baseName = jarFileName.endsWith(".jar")
90 |                 ? jarFileName.substring(0, jarFileName.length() - 4)
91 |                 : jarFileName;
92 | 
93 |         System.out.println("  Resolving: " + jarFileName + " ...");
94 | 
95 |         if (!Files.exists(path)) {
96 |             System.err.println("  [WARN] JARファイルが見つかりません: " + path
97 |                     + " → systemスコープとして扱います");
98 |             System.out.println("  → not found (system scope): " + jarFileName);
99 |             return new MavenDependency(baseName, baseName, "0.0.0", "system", jarPath);
100 |         }
101 | 
102 |         String sha1;
103 |         try {
104 |             sha1 = FileUtils.computeSha1(path);
105 |         } catch (Exception e) {
106 |             System.err.println("  [ERROR] SHA1計算に失敗しました: " + path + " → " + e.getMessage());
107 |             System.out.println("  → SHA1 error (system scope): " + jarFileName);
108 |             return new MavenDependency(baseName, baseName, "0.0.0", "system", path.toAbsolutePath().toString());
109 |         }
110 | 
111 |         try {
112 |             String json = callMavenCentralApi(sha1);
113 |             return parseResponse(json, baseName, path.toAbsolutePath().toString());
114 |         } catch (Exception e) {
115 |             System.err.println("  [ERROR] Maven Central API呼び出しに失敗しました: " + jarFileName
116 |                     + " → " + e.getMessage());
117 |             System.out.println("  → API error (system scope): " + jarFileName);
118 |             return new MavenDependency(baseName, baseName, "0.0.0", "system", path.toAbsolutePath().toString());
119 |         }
120 |     }
121 | 
122 |     /**
123 |      * Maven Central Search APIを呼び出してJSONレスポンスを返す。
124 |      * テスト用にprotectedとして定義し、サブクラスでオーバーライド可能にする。
125 |      */
126 |     protected String callMavenCentralApi(String sha1) throws IOException, InterruptedException {
127 |         String url = String.format(MAVEN_SEARCH_URL, sha1);
128 |         HttpRequest request = HttpRequest.newBuilder()
129 |                 .uri(URI.create(url))
130 |                 .timeout(Duration.ofSeconds(10))
131 |                 .GET()
132 |                 .build();
133 |         HttpResponse<String> response = httpClient.send(request, HttpResponse.BodyHandlers.ofString());
134 |         return response.body();
135 |     }
136 | 
137 |     // private static final Pattern GROUP_ID_PATTERN    = Pattern.compile("\"g\"\\s*:\\s*\"([^\"]+)\"");
138 |     // private static final Pattern ARTIFACT_ID_PATTERN = Pattern.compile("\"a\"\\s*:\\s*\"([^\"]+)\"");
139 |     // private static final Pattern VERSION_PATTERN     = Pattern.compile("\"latestVersion\"\\s*:\\s*\"([^\"]+)\"");
140 |     // private static final Pattern NUM_FOUND_PATTERN   = Pattern.compile("\"numFound\"\\s*:\\s*(\\d+)");
141 |     private static final Pattern GROUP_ID_PATTERN    = Pattern.compile("\"g\":\"([^\"]+)\"");
142 |     private static final Pattern ARTIFACT_ID_PATTERN = Pattern.compile("\"a\":\"([^\"]+)\"");
143 |     private static final Pattern VERSION_PATTERN     = Pattern.compile("\"v\":\"([^\"]+)\"");
144 |     private static final Pattern NUM_FOUND_PATTERN   = Pattern.compile("\"numFound\"\\s*:\\s*(\\d+)");
145 | 
146 |     /**
147 |      * Maven Central APIのJSONレスポンスをパースしてMavenDependencyを返す。
148 |      */
149 |     private static MavenDependency parseResponse(String json, String baseName, String absolutePath) {
150 |         // numFound:0 なら見つからなかった
151 |         Matcher numFoundMatcher = NUM_FOUND_PATTERN.matcher(json);
152 |         if (numFoundMatcher.find()) {
153 |             int numFound = Integer.parseInt(numFoundMatcher.group(1));
154 |             if (numFound == 0) {
155 |                 System.out.println("  → not found in Maven Central (system scope): " + baseName);
156 |                 return new MavenDependency(baseName, baseName, "0.0.0", "system", absolutePath);
157 |             }
158 |         }
159 | 
160 |         Matcher gMatcher = GROUP_ID_PATTERN.matcher(json);
161 |         Matcher aMatcher = ARTIFACT_ID_PATTERN.matcher(json);
162 |         Matcher vMatcher = VERSION_PATTERN.matcher(json);
163 | 
164 |         if (gMatcher.find() && aMatcher.find() && vMatcher.find()) {
165 |             String groupId    = gMatcher.group(1);
166 |             String artifactId = aMatcher.group(1);
167 |             String version    = vMatcher.group(1);
168 |             System.out.println("  → found: " + groupId + ":" + artifactId + ":" + version);
169 |             return new MavenDependency(groupId, artifactId, version, null, null);
170 |         }
171 | 
172 |         // パースに失敗した場合もsystemスコープ
173 |         System.err.println("  [WARN] Maven Central APIレスポンスのパースに失敗しました: " + baseName);
174 |         System.out.println("  → parse error (system scope): " + baseName);
175 |         return new MavenDependency(baseName, baseName, "0.0.0", "system", absolutePath);
176 |     }
177 | }
