36 | /**
37 |  * デバッグ情報を ZIP アーカイブとして出力するクラス。
38 |  *
39 |  * <p>出力内容:</p>
40 |  * <ul>
41 |  *   <li>コマンドライン引数一覧（{@code commandline_args.txt}）</li>
42 |  *   <li>実行環境のシステムプロパティ一覧（{@code system_properties.txt}）</li>
43 |  *   <li>Eclipseプロジェクトの {@code .project}，{@code .classpath}，{@code .factorypath}，
44 |  *       {@code .settings/} 以下の全ファイル</li>
45 |  *   <li>Eclipseプロジェクト内の全ファイル一覧（名前・サイズ・日付。JARの場合はSHA1も）</li>
46 |  *   <li>生成したMavenプロジェクトの {@code pom.xml}</li>
47 |  *   <li>生成したMavenプロジェクトの全ファイル一覧（名前・サイズ・日付）</li>
48 |  * </ul>
49 |  */
50 | public class DebugArchiver {
51 | 
52 |     private static final DateTimeFormatter TIMESTAMP_FMT =
53 |             DateTimeFormatter.ofPattern("yyyyMMdd_HHmmss");
54 |     private static final DateTimeFormatter FILETIME_FMT =
55 |             DateTimeFormatter.ofPattern("yyyy-MM-dd'T'HH:mm:ss");
56 | 
57 |     private DebugArchiver() {}
58 | 
59 |     /**
60 |      * デバッグ ZIP を生成して出力ディレクトリに保存する。
61 |      *
62 |      * @param inputDir  Eclipseプロジェクトのルートディレクトリ
63 |      * @param outputDir outputDir（artifactId を含まないトップレベルのディレクトリ）
64 |      * @param mavenDir  生成したMavenプロジェクトのルートディレクトリ
65 |      * @param args      コマンドライン引数のコピー
66 |      * @throws IOException ZIP生成またはファイル書き込みに失敗した場合
67 |      */
68 |     public static void archive(Path inputDir, Path outputDir, Path mavenDir, String[] args) throws IOException {
69 | 
70 |         String timestamp = LocalDateTime.now().format(TIMESTAMP_FMT);
71 |         Path zipPath = outputDir.resolve("e2m_debug_" + timestamp + ".zip");
72 |         Files.createDirectories(outputDir);
73 | 
74 |         System.out.println("\n[DEBUG] デバッグ情報を出力中: " + zipPath);
75 | 
76 |         try (OutputStream fos = Files.newOutputStream(zipPath);
77 |              ZipOutputStream zos = new ZipOutputStream(fos, StandardCharsets.UTF_8)) {
78 | 
79 |             // ── 0. コマンドライン引数一覧 ─────────────────────────────────────
80 |             addText(zos, "commandline_args.txt", buildArgsText(args));
81 | 
82 |             // ── 0b. システムプロパティ一覧 ────────────────────────────────────
83 |             addText(zos, "system_properties.txt", buildSystemPropertiesText());
84 | 
85 |             // ── 1. Eclipseプロジェクトのメタファイル ──────────────────────────
86 |             addEclipseMetaFiles(zos, inputDir);
87 | 
88 |             // ── 2. Eclipseプロジェクトのファイル一覧（JARはSHA1付き）──────────
89 |             addText(zos, "eclipse_files.json", buildEclipseFileListing(inputDir));
90 | 
91 |             // ── 3. 生成したMavenプロジェクトのpom.xml ────────────────────────
92 |             if (mavenDir != null) {
93 |                 Path pomFile = mavenDir.resolve("pom.xml");
94 |                 if (Files.isRegularFile(pomFile)) {
95 |                     addFile(zos, pomFile, "pom.xml");
96 |                 }
97 | 
98 |                 // ── 4. 生成したMavenプロジェクトのファイル一覧 ──────────────
99 |                 addText(zos, "maven_files.json", buildFileListing(mavenDir));
100 |             }
101 |         }
102 | 
103 |         System.out.println("[DEBUG] 出力完了: " + zipPath.toAbsolutePath());
104 |     }
105 | 
106 |     /**
107 |      * コマンドライン引数の一覧をテキスト形式で構築する。
108 |      * 各引数はインデックス付きで1行ずつ出力される。
109 |      *
110 |      * @param args コマンドライン引数のコピー（null または空配列も許容）
111 |      * @return テキスト表現
112 |      */
113 |     private static String buildArgsText(String[] args) {
114 |         StringBuilder sb = new StringBuilder();
115 |         sb.append("# e2m command-line arguments\n");
116 |         if (args == null || args.length == 0) {
117 |             sb.append("(no arguments)\n");
118 |         } else {
119 |             for (int i = 0; i < args.length; i++) {
120 |                 sb.append("args[").append(i).append("] = ").append(args[i]).append("\n");
121 |             }
122 |         }
123 |         return sb.toString();
124 |     }
125 | 
126 |     /**
127 |      * 実行環境の {@link System#getProperties()} を取得し、キーのアルファベット順に
128 |      * テキスト形式で構築する。
129 |      *
130 |      * @return テキスト表現
131 |      */
132 |     private static String buildSystemPropertiesText() {
133 |         StringBuilder sb = new StringBuilder();
134 |         sb.append("# Java System Properties\n");
135 |         Properties props = System.getProperties();
136 |         new TreeMap<>(props).forEach((k, v) ->
137 |                 sb.append(k).append(" = ").append(v).append("\n"));
138 |         return sb.toString();
139 |     }
140 | 
141 |     // ── プライベートヘルパー ──────────────────────────────────────────────────
142 | 
143 |     /**
144 |      * Eclipseプロジェクトのメタファイル（.project, .classpath, .factorypath,
145 |      * .settings/ 以下全て）を ZIP に追加する。
146 |      */
147 |     private static void addEclipseMetaFiles(ZipOutputStream zos, Path inputDir) throws IOException {
148 |         for (String name : new String[]{".project", ".classpath", ".factorypath"}) {
149 |             Path file = inputDir.resolve(name);
150 |             if (Files.isRegularFile(file)) {
151 |                 addFile(zos, file, "eclipse/" + name);
152 |             }
153 |         }
154 |         Path settingsDir = inputDir.resolve(".settings");
155 |         if (Files.isDirectory(settingsDir)) {
156 |             Files.walk(settingsDir)
157 |                     .filter(Files::isRegularFile)
158 |                     .sorted()
159 |                     .forEach(p -> {
160 |                         try {
161 |                             String relative = inputDir.relativize(p).toString().replace('\\', '/');
162 |                             addFile(zos, p, "eclipse/" + relative);
163 |                         } catch (IOException e) {
164 |                             throw new RuntimeException("ZIPへの追加に失敗しました: " + p, e);
165 |                         }
166 |                     });
167 |         }
168 |     }
169 | 
170 |     /**
171 |      * Eclipseプロジェクトのファイル一覧を JSON 形式で構築する。
172 |      * JARファイルの場合は sha1 フィールドも出力する。
173 |      */
174 |     private static String buildEclipseFileListing(Path root) throws IOException {
175 |         List<String> entries = new ArrayList<>();
176 | 
177 |         if (Files.exists(root)) {
178 |             for (Path p : (Iterable<Path>) Files.walk(root).sorted()::iterator) {
179 |                 BasicFileAttributes attrs = Files.readAttributes(p, BasicFileAttributes.class);
180 |                 boolean isDir = attrs.isDirectory();
181 |                 long size = isDir ? 0L : attrs.size();
182 |                 Instant instant = attrs.lastModifiedTime().toInstant();
183 |                 String modified = LocalDateTime.ofInstant(instant, ZoneId.systemDefault())
184 |                         .format(FILETIME_FMT);
185 |                 String relative = root.relativize(p).toString().replace('\\', '/');
186 |                 if (relative.isEmpty()) {
187 |                     relative = ".";
188 |                 }
189 | 
190 |                 StringBuilder entry = new StringBuilder();
191 |                 entry.append("    {");
192 |                 entry.append("\"type\":\"").append(isDir ? "directory" : "file").append("\"");
193 |                 entry.append(",\"path\":\"").append(jsonEscape(relative)).append("\"");
194 |                 entry.append(",\"size\":").append(size);
195 |                 entry.append(",\"lastModified\":\"").append(modified).append("\"");
196 | 
197 |                 if (!isDir && p.getFileName().toString().endsWith(".jar")) {
198 |                     String sha1;
199 |                     try {
200 |                         sha1 = FileUtils.computeSha1(p);
201 |                     } catch (Exception e) {
202 |                         sha1 = null;
203 |                     }
204 |                     if (sha1 != null) {
205 |                         entry.append(",\"sha1\":\"").append(sha1).append("\"");
206 |                     }
207 |                 }
208 | 
209 |                 entry.append("}");
210 |                 entries.add(entry.toString());
211 |             }
212 |         }
213 | 
214 |         StringBuilder sb = new StringBuilder();
215 |         sb.append("{\n");
216 |         sb.append("  \"root\":\"").append(jsonEscape(root.toAbsolutePath().toString())).append("\",\n");
217 |         sb.append("  \"entries\":[\n");
218 |         for (int i = 0; i < entries.size(); i++) {
219 |             sb.append(entries.get(i));
220 |             if (i < entries.size() - 1) sb.append(",");
221 |             sb.append("\n");
222 |         }
223 |         sb.append("  ]\n");
224 |         sb.append("}\n");
225 |         return sb.toString();
226 |     }
