36 |     /** コマンドライン引数のコピー（デバッグ ZIP 用）。 */
37 |     private String[] rawArgs;
38 | 
39 |     @Option(names = {"-g", "--groupId"}, required = false, description = "Maven groupId of the output project")
40 |     private String groupId;
