50 |             description = "Override maven.compiler.target in the generated pom.xml (default: taken from the Eclipse project settings)")
51 |     private JavaVersion javaTargetVersion;
52 | 
53 |     @Option(names = {"--debug"}, description = "Output debug information as e2m_debug_<datetime>.zip in the output directory")
54 |     private boolean debug;
