68 |     @Override
69 |     public Integer call() {
70 |         Path inputPath = inputDir.toPath();
71 | 
72 |         // 1. 引数の確認
73 |         if (!inputDir.isDirectory()) {
74 |             System.err.println("[ERROR] 入力ディレクトリが見つかりません: " + inputDir);
