92 |             System.out.println("\n[1/5] Eclipseプロジェクトを解析中...");
93 |             EclipseProject eclipseProject = EclipseProjectParser.parse(inputPath);
94 |             System.out.println("  プロジェクト名: " + eclipseProject.projectName());
95 |             System.out.println("  種別: " + (eclipseProject.webProject() ? "Webプロジェクト (WTP)" : "Javaプロジェクト"));
96 |             System.out.println("  Javaソースバージョン: " + eclipseProject.javaSourceVersion());
97 |             System.out.println("  Javaターゲットバージョン: " + eclipseProject.javaTargetVersion());
98 |             if (eclipseProject.webProject()) {
99 |                 System.out.println("  Web仕様バージョン: " + eclipseProject.webVersion());
100 |             }
