102 |             if (eclipseProject.webProject()) {
103 |                 System.out.println("  Webコンテンツフォルダ: " + eclipseProject.webContentRoot());
104 |             }
105 |             System.out.println("  JARファイル数: " + eclipseProject.jarPaths().size());
106 | 
107 |             if (eclipseProject.javaSourceVersion().isUnknown()) {
108 |                 System.err.println("[ERROR] Javaソースバージョンを認識できませんでした: "
109 |                         + eclipseProject.javaSourceVersion());
110 |                 return 1;
111 |             }
112 | 
113 |             System.out.println("\n[2/5] 移行先のMavenプロジェクトを決定中...");
114 |             String defaultArtifactId = convertToArtifactId(eclipseProject.projectName());
115 |             if (groupId == null || groupId.isBlank()) {
116 |                 // オプション未指定の場合は対話的に入力を受け付ける
117 |                 try (BufferedReader reader = new BufferedReader(new InputStreamReader(System.in))) {
118 |                     groupId = promptIfAbsent(reader, "groupId", groupId, null);
119 |                     artifactId = promptIfAbsent(reader, "artifactId", artifactId, defaultArtifactId);
120 |                     artifactVersion = promptIfAbsent(reader, "artifactVersion", artifactVersion, DEFAULT_ARTIFACT_VERSION);
121 |                 }
122 |             } else {
123 |                 // 少なくとも--groupIdが指定されていれば，あとは空ならデフォルトを使用する
124 |                 if (artifactId == null || artifactId.isBlank()) {
125 |                     artifactId = defaultArtifactId;
126 |                 }
127 |                 if (artifactVersion == null || artifactId.isBlank()) {
128 |                     artifactVersion = DEFAULT_ARTIFACT_VERSION;
129 |                 }
130 |                 System.out.println("groupId: " + groupId);
131 |                 System.out.println("artifactId: " + artifactId);
132 |                 System.out.println("version: " + artifactVersion);
133 |             }
134 | 
135 |             // 出力先は outputDir/artifactId
136 |             Path outputPath = outputDir.toPath().resolve(artifactId);
137 |             if (outputPath.toFile().exists()) {
138 |                 System.err.println("[ERROR] 出力先ディレクトリがすでに存在しています: " + outputPath);
139 |                 return 1;
140 |             }
141 | 
142 |             System.out.println("\n=== e2m: Eclipse → Maven 変換開始 ===");
143 |             System.out.println("  入力: " + inputPath.toAbsolutePath());
144 |             System.out.println("  出力: " + outputPath.toAbsolutePath());
145 | 
146 |             // 3.(続き) JAR依存関係を解決
147 |             System.out.println("\n[3/5] JAR依存関係を解決中...");
148 |             List<MavenDependency> dependencies = DependencyResolver.resolve(eclipseProject.jarPaths(), inputPath);
149 |             long found = dependencies.stream().filter(d -> !"system".equals(d.scope())).count();
150 |             long system = dependencies.stream().filter(d -> "system".equals(d.scope())).count();
151 |             System.out.println("  Maven Central で見つかった依存: " + found + " 件");
152 |             System.out.println("  system スコープの依存: " + system + " 件");
153 | 
154 |             // 4. pom.xml を生成
