160 |                     System.err.println("[ERROR] --javaTargetVersion (" + javaTargetVersion
161 |                             + ") はJavaソースバージョン (" + eclipseProject.javaSourceVersion()
162 |                             + ") より低いバージョンを指定することはできません。");
163 |                     return 1;
164 |                 }
165 |             }
166 |             PomGenerator.generate(eclipseProject, dependencies, groupId, artifactId, artifactVersion,
167 |                     javaTargetVersion, outputPath);
168 | 
169 |             // 5. ソース・Webコンテンツをコピー
170 |             System.out.println("\n[5/5] ソースファイルをコピー中...");
171 |             ProjectCopier.copy(eclipseProject, dependencies, inputPath, outputPath);
172 | 
173 |             System.out.println("\n=== 変換完了 ===");
174 |             System.out.println("出力先: " + outputPath.toAbsolutePath());
175 | 
176 |             // --debug オプション: デバッグ ZIP を生成
177 |             if (debug) {
178 |                 DebugArchiver.archive(inputPath, outputDir.toPath(), outputPath, rawArgs);
179 |             }
180 | 
181 |             return 0;
182 | 
183 |         } catch (Exception e) {
184 |             System.err.println("[ERROR] 変換中にエラーが発生しました: " + e.getMessage());
185 |             e.printStackTrace(System.err);
186 |             return 2;
187 |         }
188 |     }
189 | 
190 |     /**
191 |      * 引数が null または空の場合にプロンプトを表示して入力を受け付ける。
192 |      * デフォルト値がある場合は "[default]" 形式で表示し、空入力でデフォルト値を採用する。
193 |      *
194 |      * @param reader       入力ストリーム
195 |      * @param name         項目名（表示用）
196 |      * @param value        コマンドライン引数の値（null または空の場合にプロンプト表示）
197 |      * @param defaultValue デフォルト値（null の場合はデフォルトなし）
198 |      * @return 確定した値
199 |      */
200 |     private static String promptIfAbsent(BufferedReader reader, String name,
201 |             String value, String defaultValue) throws Exception {
202 |         if (value != null && !value.isBlank()) {
203 |             return value;
204 |         }
205 |         while (true) {
206 |             if (defaultValue != null) {
207 |                 System.out.print(name + " [" + defaultValue + "]: ");
208 |             } else {
209 |                 System.out.print(name + ": ");
210 |             }
211 |             System.out.flush();
212 |             String line = reader.readLine();
213 |             if (line == null) {
214 |                 // EOF（パイプ等）の場合はデフォルト値を使用
215 |                 return defaultValue != null ? defaultValue : "";
216 |             }
217 |             String trimmed = line.trim();
218 |             if (trimmed.isEmpty()) {
219 |                 if (defaultValue != null) {
220 |                     return defaultValue;
221 |                 }
222 |                 System.err.println("  値を入力してください。");
223 |                 continue;
224 |             }
225 |             return trimmed;
226 |         }
227 |     }
228 | 
229 |     // artifactIdとして許可する文字（半角英数字、ハイフン、アンダースコア）以外にマッチする正規表現
230 |     private static final Pattern INVALID_CHARS = Pattern.compile("[^a-z0-9\\-_]");
231 | 
232 |     // キャメルケースの境界（大文字の前）にマッチする正規表現
233 |     private static final Pattern CAMEL_CASE_BOUNDARY = Pattern.compile("(?<=[a-z0-9])(?=[A-Z])");
234 | 
235 |     /**
236 |      * プロジェクト名からMavenのartifactIdとして利用可能な文字列を生成します。
237 |      *
238 |      * @param projectName プロジェクト名
239 |      * @return artifactId用文字列
240 |      */
241 |     public static String convertToArtifactId(String projectName) {
242 |         if (projectName == null || projectName.isBlank()) {
243 |             return "default-artifact";
244 |         }
245 | 
246 |         // 1. パッケージ名が含まれている場合（完全限定名）、最後のクラス名部分だけを抽出
247 |         String simpleName = projectName.substring(projectName.lastIndexOf('.') + 1);
248 | 
249 |         // 2. キャメルケース（OrderManager -> Order-Manager）をハイフン区切りに変換
250 |         String kebabCase = CAMEL_CASE_BOUNDARY.matcher(simpleName).replaceAll("-");
251 | 
252 |         // 3. すべて小文字に変換
253 |         String lowerCase = kebabCase.toLowerCase();
254 | 
255 |         // 4. artifactIdとして使えない文字（日本語や特殊記号など）を完全に除去
256 |         String sanitized = INVALID_CHARS.matcher(lowerCase).replaceAll("");
257 | 
258 |         // 5. 連続したハイフンやアンダースコアを綺麗に整理
259 |         sanitized = sanitized.replaceAll("[-_]{2,}", "-");
260 | 
261 |         // 6. 先頭や末尾にあるハイフン・アンダースコアを除去
262 |         sanitized = sanitized.replaceAll("^[-_]+|[-_]+$", "");
263 | 
264 |         // すべての文字が削られて空になった場合のフォールバック
265 |         return sanitized.isBlank() ? "converted-artifact" : sanitized;
266 |     }
267 | 
268 |     /**
269 |      * picocli 用の {@link JavaVersion} 型変換クラス。
270 |      * 変換に失敗した場合は {@link JavaVersion#UNKNOWN_VERSION} を返す。
271 |      */
272 |     static class JavaVersionConverter implements ITypeConverter<JavaVersion> {
273 |         @Override
274 |         public JavaVersion convert(String value) {
275 |             return JavaVersion.of(value);
276 |         }
277 |     }
278 | }
