209 |      * DependencyResolverのprivateなresolveJarメソッドを
210 |      * スタブインスタンス経由で呼び出すヘルパー。
211 |      * <p>
212 |      * staticのresolve()は内部でnew DependencyResolver()するため、
213 |      * スタブを注入できない。そのためリフレクションで非公開メソッドを直接呼ぶ。
214 |      */
215 |     private static List<MavenDependency> invokeResolveViaReflection(
216 |             DependencyResolver resolver, List<String> jarPaths, Path inputDir) {
217 |         try {
218 |             var method = DependencyResolver.class.getDeclaredMethod(
219 |                     "resolveJar", String.class, Path.class);
220 |             method.setAccessible(true);
221 |             List<MavenDependency> results = new java.util.ArrayList<>();
222 |             for (String jarPath : jarPaths) {
223 |                 results.add((MavenDependency) method.invoke(resolver, jarPath, inputDir));
