33 | /**
34 |  * EclipseProject情報と依存関係リストからMavenのpom.xmlを生成するクラス。
35 |  */
36 | public class PomGenerator {
37 | 
38 |     private static final String MAVEN_COMPILER_PLUGIN_VERSION = "3.15.0";
39 |     private static final String MAVEN_WAR_PLUGIN_VERSION = "3.5.1";
40 | 
41 |     private PomGenerator() {}
42 | 
43 |     /**
44 |      * pom.xmlを生成して出力ディレクトリに保存する。
45 |      *
46 |      * @param eclipseProject      パース済みEclipseプロジェクト情報
47 |      * @param dependencies        解決済み依存関係リスト
48 |      * @param groupId             生成するpom.xmlのgroupId
49 |      * @param artifactId          生成するpom.xmlのartifactId
50 |      * @param version             生成するpom.xmlのversion
51 |      * @param javaTargetOverride  maven.compiler.targetに使用するJavaバージョン。
52 |      *                            nullまたはUNKNOWN_VERSIONの場合はeclipseProject.javaTargetVersion()を使用する
53 |      * @param outputDir           出力ディレクトリ
54 |      * @throws Exception XML生成またはファイル書き込みに失敗した場合
55 |      */
56 |     public static void generate(
57 |             EclipseProject eclipseProject,
58 |             List<MavenDependency> dependencies,
59 |             String groupId,
60 |             String artifactId,
61 |             String version,
62 |             JavaVersion javaTargetOverride,
63 |             Path outputDir) throws Exception {
64 | 
65 |         DocumentBuilderFactory dbf = DocumentBuilderFactory.newInstance();
66 |         DocumentBuilder db = dbf.newDocumentBuilder();
67 |         Document doc = db.newDocument();
68 | 
69 |         // <project>
70 |         Element project = doc.createElement("project");
71 |         project.setAttribute("xmlns", "http://maven.apache.org/POM/4.0.0");
72 |         project.setAttribute("xmlns:xsi", "http://www.w3.org/2001/XMLSchema-instance");
73 |         project.setAttribute("xsi:schemaLocation",
74 |                 "http://maven.apache.org/POM/4.0.0 http://maven.apache.org/xsd/maven-4.0.0.xsd");
75 |         doc.appendChild(project);
76 | 
77 |         addTextElement(doc, project, "modelVersion", "4.0.0");
78 |         addTextElement(doc, project, "groupId", groupId);
79 |         addTextElement(doc, project, "artifactId", artifactId);
80 |         addTextElement(doc, project, "version", version);
81 | 
82 |         if (eclipseProject.webProject()) {
83 |             addTextElement(doc, project, "packaging", "war");
84 |         }
85 | 
86 |         // <properties>
87 |         JavaVersion javaSourceVersion = eclipseProject.javaSourceVersion();
88 |         JavaVersion javaTargetVersion = eclipseProject.javaTargetVersion();
89 |         if (javaTargetOverride != null && !javaTargetOverride.isUnknown()) {
90 |             javaTargetVersion = javaTargetOverride;
91 |         }
92 |         Element properties = doc.createElement("properties");
93 |         addTextElement(doc, properties, "project.build.sourceEncoding", "UTF-8");
94 |         addTextElement(doc, properties, "maven.compiler.source", javaSourceVersion.toString());
95 |         addTextElement(doc, properties, "maven.compiler.target", javaTargetVersion.toString());
96 |         project.appendChild(properties);
97 | 
98 |         // <dependencies>
99 |         boolean hasDependencies = !dependencies.isEmpty() || eclipseProject.webProject();
100 |         if (hasDependencies) {
101 |             Element deps = doc.createElement("dependencies");
102 |             for (MavenDependency dep : dependencies) {
103 |                 Element dependency = doc.createElement("dependency");
104 |                 addTextElement(doc, dependency, "groupId", dep.groupId());
105 |                 addTextElement(doc, dependency, "artifactId", dep.artifactId());
106 |                 addTextElement(doc, dependency, "version", dep.version());
107 |                 if (dep.scope() != null && !dep.scope().isEmpty()) {
108 |                     addTextElement(doc, dependency, "scope", dep.scope());
109 |                 }
110 |                 if (dep.systemPath() != null) {
