152 |             addTextElement(doc, warPlugin, "version", MAVEN_WAR_PLUGIN_VERSION);
153 |             Element configuration = doc.createElement("configuration");
154 |             addTextElement(doc, configuration, "failOnMissingWebXml", "false");
155 |             warPlugin.appendChild(configuration);
156 |             plugins.appendChild(warPlugin);
157 |         }
158 |         build.appendChild(plugins);
159 |         project.appendChild(build);
160 | 
161 |         // XMLをファイルに書き出す
162 |         Files.createDirectories(outputDir);
163 |         TransformerFactory tf = TransformerFactory.newInstance();
164 |         Transformer transformer = tf.newTransformer();
165 |         transformer.setOutputProperty(OutputKeys.INDENT, "yes");
166 |         transformer.setOutputProperty(OutputKeys.ENCODING, "UTF-8");
167 |         transformer.setOutputProperty("{http://xml.apache.org/xslt}indent-amount", "2");
