19 | /**
20 |  * Javaのバージョン番号を表す不変クラス。
21 |  *
22 |  * <p>以下の形式の文字列からインスタンスを生成できる。</p>
23 |  * <ul>
24 |  *   <li>{@code "1.1"} 〜 {@code "1.8"} — Java 1〜8 を表す旧形式</li>
25 |  *   <li>{@code "5"} 〜 それ以降の整数 — Java 5 以降の新形式</li>
26 |  * </ul>
27 |  *
28 |  * <p>認識できない文字列が渡された場合は {@link #UNKNOWN_VERSION} を返す。
29 |  * {@code UNKNOWN_VERSION} は内部値 {@code -1} を持ち、全ての有効なバージョンより古い扱いになる。</p>
30 |  *
31 |  * <p>{@link Comparable} を実装しており、バージョンの大小比較が可能。</p>
32 |  */
33 | public final class JavaVersion implements Comparable<JavaVersion> {
34 | 
35 |     /**
36 |      * 認識できないバージョン文字列を表す特殊インスタンス。
37 |      * 内部値は {@code -1} であり、全ての有効な {@link JavaVersion} より小さい。
38 |      */
39 |     private static final int UNKNOWN_VERSION = -1;
40 |     public static final JavaVersion Java8 = new JavaVersion(8, "1.8");
41 |     public static final JavaVersion Java9 = new JavaVersion(9, "9");
42 | 
43 |     /** 内部的に保持する整数バージョン番号（例: 1.8 → 8、17 → 17。UNKNOWN は -1）。 */
44 |     private final int value;
45 | 
46 |     /** 元の文字列表現（toString() で返す）。 */
47 |     private final String original;
48 | 
49 |     private JavaVersion(int value, String original) {
50 |         this.value = value;
51 |         this.original = original;
52 |     }
53 | 
54 |     /**
55 |      * バージョン文字列から {@link JavaVersion} インスタンスを生成する。
56 |      *
57 |      * <p>受け付ける形式:</p>
58 |      * <ul>
59 |      *   <li>{@code "1.0"} 〜 {@code "1.8"} — Java 1〜8（旧形式）</li>
60 |      *   <li>{@code "5"} 以上の整数文字列 — Java 5 以降（新形式）</li>
61 |      * </ul>
62 |      *
63 |      * <p>認識できない文字列（null・空文字・不正な形式・負数）が渡された場合は、
64 |      * その文字列を {@code original} として保持する {@link #isUnknown()} が {@code true} を返す
65 |      * インスタンスを生成して返す。null の場合は {@code original} に {@code "null"} を使用する。</p>
66 |      *
67 |      * @param version バージョン文字列
68 |      * @return 対応する {@link JavaVersion} インスタンス。認識できない場合は {@code isUnknown() == true} のインスタンス
69 |      */
70 |     public static JavaVersion of(String version) {
71 |         if (version == null || version.isBlank()) {
72 |             return new JavaVersion(UNKNOWN_VERSION, version == null ? "null" : version.trim());
73 |         }
74 |         String v = version.trim();
75 | 
76 |         // "1.x" 形式（例: "1.8"）
77 |         if (v.startsWith("1.")) {
78 |             try {
79 |                 int minor = Integer.parseInt(v.substring(2));
80 |                 if (minor < 0 || minor > 8) {
81 |                     return new JavaVersion(UNKNOWN_VERSION, v);
82 |                 }
83 |                 return new JavaVersion(minor, v);
84 |             } catch (NumberFormatException e) {
85 |                 return new JavaVersion(UNKNOWN_VERSION, v);
86 |             }
87 |         }
88 | 
89 |         // 整数形式（例: "5", "11", "17"）
90 |         try {
91 |             int n = Integer.parseInt(v);
92 |             if (n < 5) {
93 |                 return new JavaVersion(UNKNOWN_VERSION, v);
94 |             }
95 |             if (n < 9) {
96 |                 return new JavaVersion(n, "1." + v);
97 |             } else {
98 |                 return new JavaVersion(n, v);
99 |             }
100 |         } catch (NumberFormatException e) {
101 |             return new JavaVersion(UNKNOWN_VERSION, v);
102 |         }
103 |     }
104 | 
105 |     /**
106 |      * このインスタンスが {@link #UNKNOWN_VERSION} かどうかを返す。
107 |      */
108 |     public boolean isUnknown() {
109 |         return this.value == UNKNOWN_VERSION;
110 |     }
111 | 
112 |     /**
113 |      * 内部的な整数バージョン番号を返す（例: "1.8" → 8、"17" → 17）。
114 |      */
115 |     public int toInt() {
116 |         return value;
117 |     }
118 | 
119 |     @Override
120 |     public int compareTo(JavaVersion other) {
121 |         return Integer.compare(this.value, other.value);
122 |     }
123 | 
124 |     @Override
125 |     public boolean equals(Object obj) {
126 |         if (this == obj) return true;
127 |         if (!(obj instanceof JavaVersion other)) return false;
128 |         return this.value == other.value;
129 |     }
130 | 
131 |     @Override
132 |     public int hashCode() {
133 |         return Integer.hashCode(value);
134 |     }
135 | 
136 |     /** 元の文字列表現を返す（例: {@code "1.8"}、{@code "17"}）。 */
137 |     @Override
138 |     public String toString() {
139 |         return original;
140 |     }
141 | }
