33 | /**
34 |  * EclipseProject情報と依存関係リストからMavenのpom.xmlを生成するクラス。
35 |  */
36 | public class PomGenerator {
37 | 
38 |     private static final String MAVEN_COMPILER_PLUGIN_VERSION = "3.15.0";
39 |     private static final String MAVEN_WAR_PLUGIN_VERSION = "3.5.1";
40 | 
41 |     private PomGenerator() {}
42 | 
43 |     /**
44 |      * pom.xmlを生成して出力ディレクトリに保存する。
45 |      *
46 |      * @param eclipseProject      パース済みEclipseプロジェクト情報
47 |      * @param dependencies        解決済み依存関係リスト
48 |      * @param groupId             生成するpom.xmlのgroupId
49 |      * @param artifactId          生成するpom.xmlのartifactId
50 |      * @param version             生成するpom.xmlのversion
51 |      * @param javaTargetOverride  maven.compiler.targetに使用するJavaバージョン。
52 |      *                            nullまたはUNKNOWN_VERSIONの場合はeclipseProject.javaTargetVersion()を使用する
53 |      * @param outputDir           出力ディレクトリ
54 |      * @throws Exception XML生成またはファイル書き込みに失敗した場合
55 |      */
56 |     public static void generate(
57 |             EclipseProject eclipseProject,
58 |             List<MavenDependency> dependencies,
59 |             String groupId,
60 |             String artifactId,
61 |             String version,
62 |             JavaVersion javaTargetOverride,
63 |             Path outputDir) throws Exception {
64 | 
65 |         DocumentBuilderFactory dbf = DocumentBuilderFactory.newInstance();
66 |         DocumentBuilder db = dbf.newDocumentBuilder();
67 |         Document doc = db.newDocument();
68 | 
69 |         // <project>
70 |         Element project = doc.createElement("project");
71 |         project.setAttribute("xmlns", "http://maven.apache.org/POM/4.0.0");
72 |         project.setAttribute("xmlns:xsi", "http://www.w3.org/2001/XMLSchema-instance");
73 |         project.setAttribute("xsi:schemaLocation",
74 |                 "http://maven.apache.org/POM/4.0.0 http://maven.apache.org/xsd/maven-4.0.0.xsd");
75 |         doc.appendChild(project);
76 | 
77 |         addTextElement(doc, project, "modelVersion", "4.0.0");
78 |         addTextElement(doc, project, "groupId", groupId);
79 |         addTextElement(doc, project, "artifactId", artifactId);
80 |         addTextElement(doc, project, "version", version);
81 | 
82 |         if (eclipseProject.webProject()) {
83 |             addTextElement(doc, project, "packaging", "war");
84 |         }
85 | 
86 |         // <properties>
87 |         JavaVersion javaSourceVersion = eclipseProject.javaSourceVersion();
88 |         JavaVersion javaTargetVersion = eclipseProject.javaTargetVersion();
89 |         if (javaTargetOverride != null && !javaTargetOverride.isUnknown()) {
90 |             javaTargetVersion = javaTargetOverride;
91 |         }
92 |         Element properties = doc.createElement("properties");
93 |         addTextElement(doc, properties, "project.build.sourceEncoding", "UTF-8");
94 |         addTextElement(doc, properties, "maven.compiler.source", javaSourceVersion.toString());
95 |         addTextElement(doc, properties, "maven.compiler.target", javaTargetVersion.toString());
96 |         project.appendChild(properties);
97 | 
98 |         // <dependencies>
99 |         boolean hasDependencies = !dependencies.isEmpty() || eclipseProject.webProject();
100 |         if (hasDependencies) {
101 |             Element deps = doc.createElement("dependencies");
102 |             for (MavenDependency dep : dependencies) {
103 |                 Element dependency = doc.createElement("dependency");
104 |                 addTextElement(doc, dependency, "groupId", dep.groupId());
105 |                 addTextElement(doc, dependency, "artifactId", dep.artifactId());
106 |                 addTextElement(doc, dependency, "version", dep.version());
107 |                 if (dep.scope() != null && !dep.scope().isEmpty()) {
108 |                     addTextElement(doc, dependency, "scope", dep.scope());
109 |                 }
110 |                 if (dep.systemPath() != null) {
111 |                     // system スコープの JAR は libs/ にコピーされるため ${project.basedir}/libs/<ファイル名> で参照
112 |                     String fileName = Path.of(dep.systemPath()).getFileName().toString();
113 |                     addTextElement(doc, dependency, "systemPath",
114 |                             "${project.basedir}/libs/" + fileName);
115 |                 }
116 |                 deps.appendChild(dependency);
117 |             }
118 |             // webProject の場合は Java EE / Jakarta EE API を provided で追加
119 |             if (eclipseProject.webProject() && eclipseProject.webVersion() != null) {
120 |                 String webVersion = eclipseProject.webVersion();
121 |                 boolean tooOld = webVersion.startsWith("2");
122 |                 String resolvedVersion = tooOld ? "3.0" : webVersion;
123 |                 JavaEEVersion javaEE = JavaEEVersion.of(resolvedVersion);
124 |                 Element dependency = doc.createElement("dependency");
125 |                 if (tooOld) {
126 |                     deps.appendChild(doc.createComment(
127 |                             " WARNING: Servlet " + webVersion + " は古すぎるため対応する javaee-api dependency が存在しません。"
128 |                             + " Java EE 6 (javaee-api:6.0) に置き換えています。マイグレーションが必要です。 "));
129 |                 }
130 |                 addTextElement(doc, dependency, "groupId", javaEE.getGroupId());
131 |                 addTextElement(doc, dependency, "artifactId", javaEE.getArtifactId());
132 |                 addTextElement(doc, dependency, "version", javaEE.getVersion());
133 |                 addTextElement(doc, dependency, "scope", "provided");
134 |                 deps.appendChild(dependency);
135 |             }
136 |             project.appendChild(deps);
137 |         }
138 | 
139 |         // <build><plugins><plugin> maven-compiler-plugin
140 |         Element build = doc.createElement("build");
141 |         Element plugins = doc.createElement("plugins");
142 |         Element plugin = doc.createElement("plugin");
143 |         addTextElement(doc, plugin, "groupId", "org.apache.maven.plugins");
144 |         addTextElement(doc, plugin, "artifactId", "maven-compiler-plugin");
145 |         addTextElement(doc, plugin, "version", MAVEN_COMPILER_PLUGIN_VERSION);
146 |         plugins.appendChild(plugin);
147 |         // webProject の場合は maven-war-plugin を追加
148 |         if (eclipseProject.webProject()) {
149 |             Element warPlugin = doc.createElement("plugin");
150 |             addTextElement(doc, warPlugin, "groupId", "org.apache.maven.plugins");
151 |             addTextElement(doc, warPlugin, "artifactId", "maven-war-plugin");
152 |             addTextElement(doc, warPlugin, "version", MAVEN_WAR_PLUGIN_VERSION);
153 |             Element configuration = doc.createElement("configuration");
154 |             addTextElement(doc, configuration, "failOnMissingWebXml", "false");
155 |             warPlugin.appendChild(configuration);
156 |             plugins.appendChild(warPlugin);
157 |         }
158 |         build.appendChild(plugins);
159 |         project.appendChild(build);
160 | 
161 |         // XMLをファイルに書き出す
162 |         Files.createDirectories(outputDir);
163 |         TransformerFactory tf = TransformerFactory.newInstance();
164 |         Transformer transformer = tf.newTransformer();
165 |         transformer.setOutputProperty(OutputKeys.INDENT, "yes");
166 |         transformer.setOutputProperty(OutputKeys.ENCODING, "UTF-8");
167 |         transformer.setOutputProperty("{http://xml.apache.org/xslt}indent-amount", "2");
168 | 
169 |         Path pomPath = outputDir.resolve("pom.xml");
170 |         transformer.transform(new DOMSource(doc), new StreamResult(pomPath.toFile()));
171 | 
172 |         System.out.println("Generated: " + pomPath);
173 |     }
174 | 
175 |     private static void addTextElement(Document doc, Element parent, String tagName, String text) {
176 |         Element el = doc.createElement(tagName);
177 |         el.appendChild(doc.createTextNode(text));
178 |         parent.appendChild(el);
179 |     }
180 | }
