    static boolean isTestFolder(String folderPath) {
        String lower = folderPath.toLowerCase();
        for (String segment : lower.split("[/\\\\]")) {
            if (segment.equals("test") || segment.startsWith("test-") || segment.endsWith("-test")
                    || segment.contains("test")) {
