        try {
            return Charset.forName(encodingName);
        } catch (Exception e) {
            // 不明なエンコーディング名の場合は fallback を使用
            System.out.println("  [WARN] JSP の pageEncoding が不明です: " + encodingName + " → fallback を使用");
            return fallback;
        }
    }

