     * @param from 変換元エンコーディング
     * @throws IOException ファイル読み書きに失敗した場合
     */
    static void copyPropertiesWithConversion(Path src, Path dest, Charset from) throws IOException {
        List<String> lines = Files.readAllLines(src, from);
