        // pageEncoding 属性値を UTF-8 に書き換える（シングルクォートとダブルクォートの両方に対応）
        String converted = content.replaceAll(
                "(<%@\\s*page\\b[^%]*\\bpageEncoding\\s*=\\s*)([\"'])([^\"']+)\\2",
