+        assertArrayEquals(sjisBytes, Files.readAllBytes(dest), "convertToUtf8=false ではバイナリコピーされる");
+    }
+
+    // =========================================================
+    // extractJspPageEncoding 単体テスト
+    // =========================================================
+
+    @Test
