     * @param sourceEncoding 変換元エンコーディング（.jsp の pageEncoding が不明な場合に使用）
     * @throws IOException ファイルコピーに失敗した場合
     */
    private static void copyWebContents(Path srcDir, Path destDir,
                                        boolean convertToUtf8, Charset sourceEncoding)
            throws IOException {
